      "payload.clientes": clientes,
      "payload.certificacoes": certificacoes,
      "payload.premios": premios,
      "payload.parcerias": parcerias,
      "payload.estudos_caso": estudosCaso,

      "payload.industria": industria,
      "payload.modelo_negocio": modeloNegocio,
      "payload.cobertura_geografica": cobertura,

      "payload.email": emails,
      "payload.telefone": telefones,
      "payload.site": site,
      "payload.linkedin": linkedin,
      "payload.endereco": endereco,

      "payload.cidade": municipio,
      "payload.uf": uf,
      "payload.cnpj": clean(identidade.cnpj),

      "payload.created_at": item.json.created_at,
      "payload.updated_at": item.json.updated_at
    }
  };

});

